#!/usr/bin/env bash
# Fan-out: submit small text, medium text, and whisper KNOT builds in parallel.
set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
DI="$SCRIPT_DIR/distributed-inference"

submit_one() {
  local yaml="$1"
  local label="$2"
  local TMPDIR
  TMPDIR="$(mktemp -d)"
  mkdir -p "$TMPDIR/open-source/gnosis/distributed-inference"
  cp "$yaml"                    "$TMPDIR/"
  cp "$DI/encode-knot.py"       "$TMPDIR/open-source/gnosis/distributed-inference/"
  cp "$DI/upload-to-r2.py"      "$TMPDIR/open-source/gnosis/distributed-inference/"
  echo "[$label] submitting..."
  gcloud builds submit "$TMPDIR" \
    --config="$TMPDIR/$(basename "$yaml")" \
    --project=neutral-418500 \
    --async 2>&1 | tail -3
  rm -rf "$TMPDIR"
}

submit_one "$SCRIPT_DIR/cloudbuild-text-knots-small.yaml"  "text-small"  &
submit_one "$SCRIPT_DIR/cloudbuild-text-knots-medium.yaml" "text-medium" &
submit_one "$SCRIPT_DIR/cloudbuild-whisper-knots.yaml"     "whisper"     &

wait
echo "[submit-text-knots] all queued"
